// Get all items from Merge (Extract is index 0, Analysis is index 1)
const allItems = $input.all();

// Extract data from first item (PDF Vector Extract)
const extractItem = allItems[0]?.json || {};
const billData = extractItem.data || extractItem;

// Analysis data from second item (PDF Vector Ask)
const analysisItem = allItems[1]?.json || {};
const analysis = analysisItem.markdown || analysisItem.answer || analysisItem.text || 'No analysis generated';

// Get trigger data for file info
const triggerData = $('New Medical Bill').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Format line items
const lineItems = billData.lineItems || [];
const lineItemsList = lineItems.map(item => 
  `${item.cptCode || 'N/A'}: ${item.description} - $${item.totalCharge?.toFixed(2) || '0.00'}`
).join('\n') || 'No line items extracted';

// Calculate totals
const totalBilled = billData.totalBilled || 0;
const insurancePaid = billData.insurancePaid || 0;
const patientResp = billData.patientResponsibility || 0;

// Count potential issues from analysis
let issueCount = 0;
let priority = 'Low';
const analysisLower = analysis.toLowerCase();
if (analysisLower.includes('duplicate')) issueCount++;
if (analysisLower.includes('unbundling')) issueCount++;
if (analysisLower.includes('upcoding')) issueCount++;
if (analysisLower.includes('overcharge')) issueCount++;
if (analysisLower.includes('error')) issueCount++;

if (issueCount >= 3) priority = 'High';
else if (issueCount >= 1) priority = 'Medium';

return [{
  json: {
    providerName: billData.providerName || 'Unknown Provider',
    patientName: billData.patientName || 'Unknown',
    accountNumber: billData.accountNumber || 'N/A',
    dateOfService: billData.dateOfService || 'N/A',
    admissionDate: billData.admissionDate || 'N/A',
    dischargeDate: billData.dischargeDate || 'N/A',
    totalBilled: totalBilled,
    insurancePaid: insurancePaid,
    patientResponsibility: patientResp,
    paymentDueDate: billData.paymentDueDate || 'N/A',
    lineItemCount: lineItems.length,
    lineItemsList: lineItemsList,
    facilityCharges: billData.facilityCharges || 0,
    physicianCharges: billData.physicianCharges || 0,
    pharmacyCharges: billData.pharmacyCharges || 0,
    supplyCharges: billData.supplyCharges || 0,
    analysisReport: analysis,
    issueCount: issueCount,
    disputePriority: priority,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

